// Test stackalloc with Span<nint> and Span<nuint>
Span<nint> signed = stackalloc nint[5];
for (int i = 0; i < signed.Length; i++)
    signed[i] = i * 10;

Span<nuint> unsigned = stackalloc nuint[5];
for (int i = 0; i < unsigned.Length; i++)
    unsigned[i] = (nuint)(i * 100);

Console.WriteLine($"nint size: {sizeof(nint)} bytes");
Console.WriteLine($"Span<nint>: [{string.Join(", ", signed.ToArray())}]");
Console.WriteLine($"Span<nuint>: [{string.Join(", ", unsigned.ToArray())}]");

